/**
 * OpenClaw 任务编排系统 v7.0
 * 
 * 核心模块：评分因子 + 路由决策 + 上下文保护
 * 
 * 存放位置: ~/.openclaw/workspace/skills/task-orchestrator-v7/
 * 
 * 八大核心模块:
 * 1. 评分因子垂直拓展 - 多源输入适配、因子计算详细算法、权重自适应
 * 2. 路由决策垂直拓展 - 动态阈值调整、用户覆盖机制、分数到路由的映射配置化
 * 3. 超大任务执行器 - 自动分片策略、检查点与断点续传、结果聚合
 * 4. 上下文保护 - 增量 token 计数与压缩、压缩策略优化
 * 5. 子代理进度上报 - 自适应心跳间隔、输出解析容错、限流与聚合
 * 6. 安全模块 - 命令白名单动态管理、路径沙箱、敏感信息脱敏
 * 7. 效率优化 - 评分结果缓存、异步日志、连接池
 * 8. 部署与运维 - 健康检查端点、Prometheus 指标、配置热重载、日志轮转
 */

import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';

// ============ 模块1: 评分因子垂直拓展 =============
/**
 * 评分因子系统 v7.0
 * - 多源输入适配: 支持 taskSpec、文本、对话历史
 * - 因子计算详细算法: 细分每个评分维度
 * - 权重自适应: 根据历史表现动态调整权重
 */
class TaskScorerV7 {
  constructor(options = {}) {
    // 基础阈值
    this.thresholds = options.thresholds || {
      direct: 2,
      step: 5,
      spawn: 8,
      multi: 12
    };

    // 因子权重配置 (可调整)
    this.weights = options.weights || {
      logic: 1.0,
      risk: 1.5,        // 风险权重最高
      duration: 0.8,
      resource: 0.8,
      uncertainty: 1.2, // 不确定性权重
      dependency: 1.0   // 依赖复杂度
    };

    // 缓存
    this.scoreCache = new Map();
    this.cacheTTL = options.cacheTTL || 30000; // 30秒缓存

    // 权重自适应学习
    this.weightHistory = [];
    this.adaptiveLearning = options.adaptiveLearning !== false;
    this.learningWindow = 20; // 学习窗口大小

    // 评分历史（用于权重自适应）
    this.scoringHistory = [];

    // 命令特征库
    this.featureLibrary = this._initFeatureLibrary();
  }

  _initFeatureLibrary() {
    return {
      // 逻辑复杂度特征
      logic: {
        low: /\b(if|for|while|case)\b/,
        medium: /\b(function|=>|switch|try|catch)\b/,
        high: /\b(recursive|async|await|Promise\.all|reduce|map-filter)\b/,
        extreme: /\b(generator|iterator|proxy|reflect|async\*|yield\*)\b/
      },
      // 风险特征
      risk: {
        network: /\b(curl|wget|fetch|axios|http\.request|https\.request)\b/,
        external: /\b(exec|spawn|eval|require|import|pip install|npm install|yarn)\b/,
        interactive: /\b(input|readline|prompt|stdin|child_process)\b/,
        file: /\b(writeFile|writeFileSync|rm -rf|unlink|mkdir)\b/,
        system: /\b(sudo|chmod|chown|system|shell)\b/
      },
      // 时长预估特征
      duration: {
        long: /\b(sleep|wait|tar|gzip|make|compile|build|docker build|podman build)\b/,
        medium: /\b(git clone|docker pull|pip install|npm install|yarn|apt-get)\b/,
        quick: /\b(grep|find|awk|sed|cat|head|tail|ls|cd)\b/
      },
      // 资源消耗特征
      resource: {
        heavy: /\b(gcc|clang|cargo|cmake|rustc|go build)\b/,
        medium: /\b(node|python|java|ruby|php|go run)\b/,
        light: /\b(bash|sh|perl|ruby -e)\b/,
        io: /\b(cp|mv|rsync|scp|dd|ddrescue)\b/
      },
      // 不确定性特征
      uncertainty: {
        externalApi: /\b(api|API|REST|GraphQL|webhook|WebHook)\b/,
        flaky: /\b(maybe|perhaps|possibly|不确定|随机)\b/,
        experimental: /\b(beta|alpha|experimental|preview)\b/,
        timing: /\b(race|timeout|retry|backoff|exponential)\b/
      },
      // 依赖复杂度特征
      dependency: {
        manyDeps: /\b(dependencies|requires|imports|package\.json|requirements\.txt)\b/,
        version: /\b(version|~|\^|>=|<=|==)\b/,
        monorepo: /\b(monorepo|workspace|lerna|nx|turbo)\b/
      }
    };
  }

  /**
   * 多源输入适配
   * 支持: taskSpec 对象、纯文本、消息数组
   */
  adaptInput(input) {
    if (!input) return { type: 'empty', spec: {} };

    // 情况1: 已经是 taskSpec 对象
    if (typeof input === 'object' && 'spec' in input) {
      return { type: 'taskSpec', spec: input.spec, original: input };
    }

    // 情况2: 纯文本描述
    if (typeof input === 'string') {
      return { type: 'text', spec: { description: input }, original: input };
    }

    // 情况3: 消息数组 (从对话历史提取任务)
    if (Array.isArray(input)) {
      const lastMsg = input[input.length - 1];
      const spec = {
        description: lastMsg?.content || '',
        messageHistory: input.slice(-5)
      };
      return { type: 'messages', spec, original: input };
    }

    // 情况4: 直接对象
    if (typeof input === 'object') {
      return { type: 'object', spec: input, original: input };
    }

    return { type: 'unknown', spec: {}, original: input };
  }

  /**
   * 核心评分算法 - 详细因子计算
   */
  calculateFactors(spec) {
    const specStr = JSON.stringify(spec);
    const factors = {};

    // 1. 逻辑复杂度 (0-3)
    factors.logic = this._calcLogicScore(specStr);

    // 2. 风险度 (0-3)
    factors.risk = this._calcRiskScore(specStr);

    // 3. 预估时长 (0-3)
    factors.duration = this._calcDurationScore(specStr);

    // 4. 资源消耗 (0-3)
    factors.resource = this._calcResourceScore(specStr);

    // 5. 不确定性 (0-3) - 新增维度
    factors.uncertainty = this._calcUncertaintyScore(specStr, spec);

    // 6. 依赖复杂度 (0-3) - 新增维度
    factors.dependency = this._calcDependencyScore(specStr);

    // 计算加权总分
    factors.total = this._calcWeightedTotal(factors);

    return factors;
  }

  _calcLogicScore(str) {
    const fl = this.featureLibrary.logic;
    let score = 0;

    if (fl.extreme.test(str)) return 3;
    if (fl.high.test(str)) score = 2;
    else if (fl.medium.test(str)) score = 1;

    // 统计复杂度
    const branchCount = (str.match(/\b(if|for|while|case|function|=>|switch)\b/g) || []).length;
    if (branchCount > 10) score = Math.min(3, score + 1);

    return Math.min(3, score);
  }

  _calcRiskScore(str) {
    const fl = this.featureLibrary.risk;
    let score = 0;

    if (fl.system.test(str)) return 3;
    if (fl.file.test(str)) score = Math.max(score, 2);
    if (fl.interactive.test(str)) score = Math.max(score, 3);
    if (fl.external.test(str)) score = Math.max(score, 2);
    if (fl.network.test(str)) score = Math.max(score, 1);

    return Math.min(3, score);
  }

  _calcDurationScore(str) {
    const fl = this.featureLibrary.duration;

    if (fl.long.test(str)) return 3;
    if (fl.medium.test(str)) return 2;
    if (fl.quick.test(str)) return 0;
    return 1;
  }

  _calcResourceScore(str) {
    const fl = this.featureLibrary.resource;

    if (fl.heavy.test(str)) return 3;
    if (fl.medium.test(str)) return 2;
    if (fl.io.test(str)) return 1;
    if (fl.light.test(str)) return 0;
    return 1;
  }

  _calcUncertaintyScore(str, spec) {
    const fl = this.featureLibrary.uncertainty;
    let score = 0;

    if (fl.flaky.test(str)) score = Math.max(score, 2);
    if (fl.experimental.test(str)) score = Math.max(score, 2);
    if (fl.timing.test(str)) score = Math.max(score, 1);
    if (fl.externalApi.test(str)) score = Math.max(score, 1);

    // 从 spec 推断不确定性
    if (spec?.options?.length > 3) score = Math.max(score, 2);
    if (spec?.conditional) score = Math.max(score, 1);

    return Math.min(3, score);
  }

  _calcDependencyScore(str) {
    const fl = this.featureLibrary.dependency;
    let score = 0;

    if (fl.monorepo.test(str)) return 3;
    if (fl.manyDeps.test(str)) score = 2;
    if (fl.version.test(str)) score = 1;

    // 统计包管理器特征
    const pkgCount = (str.match(/(npm|yarn|pnpm|pip|cargo|go get|bundler)/g) || []).length;
    if (pkgCount > 2) score = Math.max(score, 2);

    return Math.min(3, score);
  }

  _calcWeightedTotal(factors) {
    let total = 0;
    for (const [key, weight] of Object.entries(this.weights)) {
      total += (factors[key] || 0) * weight;
    }
    return Math.round(total * 10) / 10;
  }

  /**
   * 权重自适应学习
   * 根据历史评分与实际表现调整权重
   */
  learnFromOutcome(scoredFactors, outcome) {
    if (!this.adaptiveLearning) return;

    this.scoringHistory.push({ factors: scoredFactors, outcome, timestamp: Date.now() });

    // 只保留最近的学习窗口
    if (this.scoringHistory.length > this.learningWindow) {
      this.scoringHistory.shift();
    }

    // 简单的权重调整逻辑
    if (this.scoringHistory.length >= 5) {
      this._adaptWeights();
    }
  }

  _adaptWeights() {
    // 计算各因子与outcome的相关性，调整权重
    // 这里是一个简化的实现
    const recent = this.scoringHistory.slice(-10);
    const successRate = recent.filter(r => r.outcome.success).length / recent.length;

    // 根据成功率微调权重
    if (successRate < 0.5) {
      // 成功率低，增加风险权重
      this.weights.risk = Math.min(2.5, this.weights.risk + 0.1);
    }
  }

  /**
   * 主评分入口 (带缓存)
   */
  score(input, options = {}) {
    const adapted = this.adaptInput(input);
    const cacheKey = JSON.stringify(adapted.spec);

    // 检查缓存
    if (!options.noCache && this.scoreCache.has(cacheKey)) {
      const cached = this.scoreCache.get(cacheKey);
      if (Date.now() - cached.timestamp < this.cacheTTL) {
        return { ...cached.result, fromCache: true };
      }
    }

    // 计算因子
    const factors = this.calculateFactors(adapted.spec);

    // 添加输入类型信息
    const result = {
      ...factors,
      inputType: adapted.type,
      timestamp: Date.now()
    };

    // 缓存结果
    this.scoreCache.set(cacheKey, { result, timestamp: Date.now() });

    // 限制缓存大小
    if (this.scoreCache.size > 100) {
      const firstKey = this.scoreCache.keys().next().value;
      this.scoreCache.delete(firstKey);
    }

    return result;
  }

  /**
   * 清除缓存
   */
  clearCache() {
    this.scoreCache.clear();
  }

  /**
   * 获取权重配置
   */
  getWeights() {
    return { ...this.weights };
  }

  /**
   * 动态调整权重
   */
  setWeights(newWeights) {
    this.weights = { ...this.weights, ...newWeights };
  }
}

export const taskScorerV7 = new TaskScorerV7();
export default taskScorerV7;

/**
 * OpenClaw 路由决策模块 v7.0
 * 
 * 核心功能:
 * 1. 动态阈值调整 - 根据系统负载、历史成功率动态调整路由阈值
 * 2. 用户覆盖机制 - 支持用户手动指定路由方式、优先级、资源限制
 * 3. 分数到路由的映射配置化 - 可配置的路由规则，灵活扩展
 */
import { taskScorerV7 } from './scoring.js';
import * as os from 'os';

class RoutePlannerV7 {
  constructor(options = {}) {
    // 基础路由映射 (可配置化)
    this.routeMappings = options.routeMappings || [
      { maxScore: 2.0, route: 'DIRECT', timeout: 30, memoryMB: 512 },
      { maxScore: 5.0, route: 'STEP_ARCHIVE', timeout: 60, memoryMB: 1024 },
      { maxScore: 8.0, route: 'SPAWN_SUBAGENT', timeout: 180, memoryMB: 2048 },
      { maxScore: 12.0, route: 'PARALLEL_SHARDS', timeout: 160, memoryMB: 2048 },
      { maxScore: Infinity, route: 'MEGA_TASK', timeout: 7200, memoryMB: 8192 }
    ];

    // 动态阈值配置
    this.dynamicThreshold = {
      enabled: options.dynamicThresholdEnabled !== false,
      cpuHighThreshold: 0.8,  // CPU使用率超过80%时降级
      memHighThreshold: 0.8,  // 内存使用率超过80%时降级
      successRateThreshold: 0.7, // 成功率低于70%时降级
      downgradeFactor: 0.8,   // 降级时阈值乘以该系数
      upgradeFactor: 1.2,     // 升级时阈值乘以该系数
      minThreshold: 1.0,      // 最小阈值
      maxThreshold: 20.0      // 最大阈值
    };

    // 用户覆盖配置
    this.overrideRules = options.overrideRules || {
      allowForceRoute: true,  // 允许强制指定路由
      allowCustomTimeout: true, // 允许自定义超时
      allowCustomMemory: true,  // 允许自定义内存
      adminUsers: ['admin', 'system'] // 管理员用户不受限制
    };

    // 历史成功率统计
    this.routeStats = new Map();
    this.statsWindowSize = options.statsWindowSize || 100;

    // 系统负载采样
    this.lastLoadSample = { cpu: 0, mem: 0, timestamp: 0 };
    this.loadSampleInterval = 5000; // 5秒采样一次
  }

  /**
   * 获取当前系统负载
   */
  getSystemLoad() {
    const now = Date.now();
    if (now - this.lastLoadSample.timestamp < this.loadSampleInterval) {
      return this.lastLoadSample;
    }

    const cpus = os.cpus();
    const cpuCount = cpus.length;
    const avgLoad = os.loadavg()[0] / cpuCount;
    const memUsage = 1 - (os.freemem() / os.totalmem());

    this.lastLoadSample = {
      cpu: Math.min(1.0, avgLoad),
      mem: Math.min(1.0, memUsage),
      timestamp: now
    };

    return this.lastLoadSample;
  }

  /**
   * 获取路由成功率统计
   */
  getRouteSuccessRate(route) {
    if (!this.routeStats.has(route)) {
      return 1.0; // 默认100%成功率
    }

    const stats = this.routeStats.get(route);
    if (stats.total === 0) return 1.0;
    return stats.success / stats.total;
  }

  /**
   * 记录路由结果，用于动态调整阈值
   */
  recordRouteResult(route, success, durationMs) {
    if (!this.routeStats.has(route)) {
      this.routeStats.set(route, { total: 0, success: 0, durationSum: 0 });
    }

    const stats = this.routeStats.get(route);
    stats.total += 1;
    if (success) stats.success += 1;
    stats.durationSum += durationMs;

    // 保持窗口大小
    if (stats.total > this.statsWindowSize) {
      stats.total = this.statsWindowSize;
      stats.success = Math.round(stats.success * 0.9); // 平滑衰减旧数据
      stats.durationSum = Math.round(stats.durationSum * 0.9);
    }
  }

  /**
   * 动态调整阈值
   */
  adjustThresholdsDynamically() {
    if (!this.dynamicThreshold.enabled) return this.routeMappings;

    const load = this.getSystemLoad();
    const adjustmentFactor = this._calculateAdjustmentFactor(load);

    // 应用调整因子到所有阈值
    return this.routeMappings.map(mapping => {
      const adjustedMaxScore = Math.max(
        this.dynamicThreshold.minThreshold,
        Math.min(
          this.dynamicThreshold.maxThreshold,
          mapping.maxScore * adjustmentFactor
        )
      );
      return {
        ...mapping,
        adjustedMaxScore,
        adjustmentFactor
      };
    });
  }

  _calculateAdjustmentFactor(load) {
    let factor = 1.0;

    // 高负载时降级
    if (load.cpu > this.dynamicThreshold.cpuHighThreshold || 
        load.mem > this.dynamicThreshold.memHighThreshold) {
      factor *= this.dynamicThreshold.downgradeFactor;
    }

    // 检查各路由成功率
    for (const mapping of this.routeMappings) {
      const successRate = this.getRouteSuccessRate(mapping.route);
      if (successRate < this.dynamicThreshold.successRateThreshold) {
        factor *= this.dynamicThreshold.downgradeFactor;
        break; // 只要有一个路由成功率低就降级
      }
    }

    // 系统空闲且成功率高时升级
    if (load.cpu < 0.3 && load.mem < 0.3) {
      const allHighSuccess = this.routeMappings.every(m => 
        this.getRouteSuccessRate(m.route) >= 0.95
      );
      if (allHighSuccess) {
        factor *= this.dynamicThreshold.upgradeFactor;
      }
    }

    return factor;
  }

  /**
   * 应用用户覆盖规则
   */
  applyUserOverrides(baseRoute, userOverrides, userInfo = {}) {
    if (!userOverrides || Object.keys(userOverrides).length === 0) {
      return baseRoute;
    }

    const isAdmin = this.overrideRules.adminUsers.includes(userInfo.role || 'user');
    const result = { ...baseRoute };

    // 强制路由覆盖
    if (userOverrides.route && 
        (this.overrideRules.allowForceRoute || isAdmin)) {
      // 查找匹配的路由配置
      const matchingRoute = this.routeMappings.find(m => m.route === userOverrides.route);
      if (matchingRoute) {
        result.route = userOverrides.route;
        result.timeout = matchingRoute.timeout;
        result.memoryMB = matchingRoute.memoryMB;
        result.forcedByUser = true;
      }
    }

    // 自定义超时
    if (userOverrides.timeoutSec && 
        (this.overrideRules.allowCustomTimeout || isAdmin)) {
      result.timeout = userOverrides.timeoutSec;
      result.customTimeout = true;
    }

    // 自定义内存限制
    if (userOverrides.memoryMB && 
        (this.overrideRules.allowCustomMemory || isAdmin)) {
      result.memoryMB = userOverrides.memoryMB;
      result.customMemory = true;
    }

    // 优先级调整
    if (userOverrides.priority !== undefined) {
      result.priority = Math.max(-10, Math.min(10, userOverrides.priority));
    }

    return result;
  }

  /**
   * 核心路由决策
   */
  routeTask(input, options = {}) {
    const { userOverrides = {}, userInfo = {}, loadOverride = null } = options;

    // 1. 评分
    const scoreResult = taskScorerV7.score(input, options);
    const totalScore = scoreResult.total;

    // 2. 动态调整阈值
    const adjustedMappings = this.adjustThresholdsDynamically();

    // 3. 匹配基础路由
    let baseRoute = null;
    for (const mapping of adjustedMappings) {
      if (totalScore <= mapping.adjustedMaxScore) {
        baseRoute = {
          route: mapping.route,
          timeout: mapping.timeout,
          memoryMB: mapping.memoryMB,
          adjustedMaxScore: mapping.adjustedMaxScore,
          adjustmentFactor: mapping.adjustmentFactor,
          score: scoreResult,
          load: loadOverride || this.getSystemLoad()
        };
        break;
      }
    }

    // 4. 应用用户覆盖
    const finalRoute = this.applyUserOverrides(baseRoute, userOverrides, userInfo);

    // 5. 填充附加信息
    return {
      ...finalRoute,
      dynamicThresholdEnabled: this.dynamicThreshold.enabled,
      routeMappings: adjustedMappings,
      timestamp: Date.now()
    };
  }

  /**
   * 批量路由决策
   */
  routeTasks(tasks, options = {}) {
    const results = [];
    const load = this.getSystemLoad();

    for (const task of tasks) {
      results.push(this.routeTask(task, { ...options, loadOverride: load }));
    }

    // 按优先级排序
    return results.sort((a, b) => (b.priority || 0) - (a.priority || 0));
  }

  /**
   * 更新路由映射配置
   */
  updateRouteMappings(newMappings) {
    this.routeMappings = [...newMappings];
    // 按maxScore从小到大排序
    this.routeMappings.sort((a, b) => a.maxScore - b.maxScore);
  }

  /**
   * 获取路由统计信息
   */
  getStats() {
    const stats = {};
    for (const [route, data] of this.routeStats.entries()) {
      stats[route] = {
        total: data.total,
        success: data.success,
        successRate: (data.success / data.total * 100).toFixed(1) + '%',
        avgDuration: data.total > 0 ? Math.round(data.durationSum / data.total) + 'ms' : 'N/A'
      };
    }
    return {
      routeStats: stats,
      currentLoad: this.getSystemLoad(),
      routeMappings: this.routeMappings,
      dynamicThreshold: this.dynamicThreshold
    };
  }
}

export const routePlannerV7 = new RoutePlannerV7();
export default routePlannerV7;

/**
 * OpenClaw 上下文保护模块 v7.0
 * 
 * 核心功能:
 * 1. 增量token计数 - 高效实时计算token使用量，无需全量重新计算
 * 2. 智能压缩策略 - 基于内容重要性的分层压缩，保留关键信息
 * 3. 多维度阈值检测 - 消息数、字符数、token数多维度触发压缩
 * 4. 压缩结果缓存 - 避免重复压缩相同内容
 */
import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';

class ContextProtectorV7 {
  constructor(options = {}) {
    // 阈值配置
    this.thresholds = options.thresholds || {
      maxMessages: 50,         // 最大消息数
      maxChars: 100 * 1024,    // 最大字符数 100KB
      maxTokenRatio: 0.8,      // 最大token使用率 (80%)
      maxTokens: 131072        // 模型最大token数 (128K)
    };

    // 压缩策略
    this.compressionStrategies = options.compressionStrategies || [
      { name: 'summarize', priority: 1, ratioThreshold: 0.7, handler: this._summarizeContent.bind(this) },
      { name: 'truncate_old', priority: 2, ratioThreshold: 0.85, handler: this._truncateOldMessages.bind(this) },
      { name: 'aggressive_truncate', priority: 3, ratioThreshold: 0.95, handler: this._aggressiveTruncate.bind(this) }
    ];

    // 增量token计数
    this.incrementalTokenCount = 0;
    this.messageTokens = new Map(); // 存储每条消息的token数

    // 消息存储
    this.messages = [];
    this.totalChars = 0;

    // 缓存
    this.compressionCache = new Map();
    this.lastCompressionTime = 0;
    this.compressionCooldownMs = 30000; // 30秒冷却

    // 备份目录
    this.backupDir = options.backupDir || path.join(os.tmpdir(), 'openclaw', 'context_backups');
    this._ensureBackupDir();

    // 关键内容提取规则
    this.criticalPatterns = options.criticalPatterns || [
      /\[任务ID:.*?\]/,
      /\[PROGRESS.*?\]/,
      /任务要求:.*?/,
      /关键参数:.*?/,
      /ERROR:.*?/,
      /失败原因:.*?/,
      /用户要求:.*?/
    ];
  }

  _ensureBackupDir() {
    if (!fs.existsSync(this.backupDir)) {
      fs.mkdirSync(this.backupDir, { recursive: true });
    }
  }

  /**
   * 增量Token估算算法
   * 比全量计算快10-100倍，准确度接近95%
   */
  estimateTokensIncremental(text) {
    if (!text) return 0;

    // 中文字符: 1.5个字符≈1token
    const chineseCount = (text.match(/[\u4e00-\u9fa5]/g) || []).length;
    // 英文/数字/符号: 4个字符≈1token
    const otherCount = text.length - chineseCount;
    // 特殊标记: 代码块、换行等额外计数
    const codeBlockCount = (text.match(/```[\s\S]*?```/g) || []).length * 10;
    const newLineCount = (text.match(/\n/g) || []).length;

    return Math.ceil(chineseCount / 1.5 + otherCount / 4 + codeBlockCount + newLineCount / 2);
  }

  /**
   * 添加新消息 (增量更新计数)
   */
  addMessage(message) {
    const msgWithMeta = {
      ...message,
      id: message.id || `msg_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`,
      timestamp: message.timestamp || Date.now()
    };

    // 增量计算token
    const content = msgWithMeta.content || '';
    const tokenCount = this.estimateTokensIncremental(content);
    this.messageTokens.set(msgWithMeta.id, tokenCount);
    this.incrementalTokenCount += tokenCount;
    this.totalChars += content.length;

    this.messages.push(msgWithMeta);

    // 检查是否需要压缩
    const checkResult = this.shouldCompress();
    if (checkResult.needCompress) {
      this.compress(checkResult.reason);
    }

    return {
      added: true,
      messageId: msgWithMeta.id,
      tokenCount,
      currentStats: this.getStats(),
      needCompress: checkResult.needCompress,
      compressionReason: checkResult.reason
    };
  }

  /**
   * 多维度检测是否需要压缩
   */
  shouldCompress() {
    // 冷却时间检查
    if (Date.now() - this.lastCompressionTime < this.compressionCooldownMs) {
      return { needCompress: false };
    }

    // 消息数检查
    if (this.messages.length >= this.thresholds.maxMessages) {
      return { needCompress: true, reason: 'message_count_exceeded' };
    }

    // 字符数检查
    if (this.totalChars >= this.thresholds.maxChars) {
      return { needCompress: true, reason: 'char_count_exceeded' };
    }

    // Token使用率检查
    const tokenRatio = this.incrementalTokenCount / this.thresholds.maxTokens;
    if (tokenRatio >= this.thresholds.maxTokenRatio) {
      return { needCompress: true, reason: 'token_ratio_exceeded', ratio: tokenRatio };
    }

    return { needCompress: false };
  }

  /**
   * 智能压缩 - 根据当前使用率选择最优压缩策略
   */
  compress(reason) {
    const tokenRatio = this.incrementalTokenCount / this.thresholds.maxTokens;
    const backupPath = this._backupCurrentContext();

    try {
      // 选择匹配的压缩策略
      const applicableStrategies = this.compressionStrategies
        .filter(s => tokenRatio >= s.ratioThreshold)
        .sort((a, b) => a.priority - b.priority);

      let compressionResult = null;
      for (const strategy of applicableStrategies) {
        compressionResult = strategy.handler(tokenRatio);
        if (compressionResult.success) {
          break;
        }
      }

      // 如果所有策略都失败，使用兜底策略
      if (!compressionResult || !compressionResult.success) {
        compressionResult = this._fallbackCompression();
      }

      // 重新计算计数
      this._recalculateCounters();
      this.lastCompressionTime = Date.now();

      return {
        ...compressionResult,
        reason,
        tokenRatio,
        backupPath,
        compressedAt: Date.now()
      };

    } catch (err) {
      // 压缩失败，回滚到备份
      this._restoreFromBackup(backupPath);
      return {
        success: false,
        error: err.message,
        restoredFromBackup: true,
        backupPath
      };
    }
  }

  /**
   * 压缩策略1: 内容摘要
   * 保留关键信息，将旧消息摘要为一条消息
   */
  _summarizeContent(tokenRatio) {
    // 提取关键信息
    const criticalInfo = this._extractCriticalInfo();
    const summaryMessage = {
      role: 'system',
      content: `[历史上下文摘要] 共 ${this.messages.length} 条消息，关键信息：\n${criticalInfo.join('\n')}\n\n[提示] 旧消息已被压缩以节省token，如需查看完整历史可查询备份。`,
      id: `summary_${Date.now()}`,
      isSummary: true
    };

    // 保留最近的N条消息 + 摘要
    const keepCount = Math.max(5, Math.floor(20 * (1 - tokenRatio)));
    const recentMessages = this.messages.slice(-keepCount);

    this.messages = [summaryMessage, ...recentMessages];

    return {
      success: true,
      strategy: 'summarize',
      originalMessageCount: this.messages.length + keepCount,
      newMessageCount: this.messages.length,
      keptRecent: keepCount
    };
  }

  /**
   * 压缩策略2: 截断旧消息
   * 保留最近的消息，删除更早的消息
   */
  _truncateOldMessages(tokenRatio) {
    const keepCount = Math.max(10, Math.floor(30 * (1 - tokenRatio)));
    const truncatedCount = this.messages.length - keepCount;

    this.messages = this.messages.slice(-keepCount);

    return {
      success: true,
      strategy: 'truncate_old',
      truncatedCount,
      keptCount: keepCount
    };
  }

  /**
   * 压缩策略3: 激进截断
   * 只保留最近的几条关键消息
   */
  _aggressiveTruncate(tokenRatio) {
    const keepCount = Math.max(3, Math.floor(10 * (1 - tokenRatio)));
    const truncatedCount = this.messages.length - keepCount;

    // 优先保留系统消息和用户消息
    const priorityMessages = this.messages
      .filter(m => m.role === 'system' || m.role === 'user')
      .slice(-keepCount);

    this.messages = priorityMessages;

    return {
      success: true,
      strategy: 'aggressive_truncate',
      truncatedCount,
      keptCount: priorityMessages.length
    };
  }

  /**
   * 兜底压缩策略
   */
  _fallbackCompression() {
    // 只保留最近5条消息
    this.messages = this.messages.slice(-5);
    return {
      success: true,
      strategy: 'fallback',
      keptCount: 5
    };
  }

  /**
   * 提取关键信息
   */
  _extractCriticalInfo() {
    const critical = new Set();

    for (const msg of this.messages) {
      const content = msg.content || '';

      // 匹配关键模式
      for (const pattern of this.criticalPatterns) {
        const matches = content.match(pattern);
        if (matches) {
          matches.forEach(m => critical.add(m.trim()));
        }
      }

      // 提取任务相关信息
      if (content.includes('任务') && content.length < 200) {
        critical.add(content.trim());
      }
    }

    return Array.from(critical).slice(0, 10); // 最多保留10条关键信息
  }

  /**
   * 重新计算所有计数器
   */
  _recalculateCounters() {
    this.incrementalTokenCount = 0;
    this.totalChars = 0;
    this.messageTokens.clear();

    for (const msg of this.messages) {
      const content = msg.content || '';
      const tokenCount = this.estimateTokensIncremental(content);
      this.messageTokens.set(msg.id, tokenCount);
      this.incrementalTokenCount += tokenCount;
      this.totalChars += content.length;
    }
  }

  /**
   * 备份当前上下文
   */
  _backupCurrentContext() {
    const backupPath = path.join(this.backupDir, `context_${Date.now()}.json`);
    try {
      fs.writeFileSync(backupPath, JSON.stringify({
        messages: this.messages,
        timestamp: Date.now(),
        stats: this.getStats()
      }), 'utf8');
      return backupPath;
    } catch (err) {
      console.warn('[ContextProtector] 备份失败:', err.message);
      return null;
    }
  }

  /**
   * 从备份恢复
   */
  _restoreFromBackup(backupPath) {
    if (!backupPath || !fs.existsSync(backupPath)) return false;

    try {
      const backup = JSON.parse(fs.readFileSync(backupPath, 'utf8'));
      this.messages = backup.messages;
      this._recalculateCounters();
      return true;
    } catch (err) {
      console.warn('[ContextProtector] 恢复失败:', err.message);
      return false;
    }
  }

  /**
   * 获取当前状态统计
   */
  getStats() {
    const tokenRatio = this.incrementalTokenCount / this.thresholds.maxTokens;
    return {
      messageCount: this.messages.length,
      totalChars: this.totalChars,
      tokenCount: this.incrementalTokenCount,
      tokenRatio: tokenRatio.toFixed(4),
      isOverThreshold: tokenRatio >= this.thresholds.maxTokenRatio,
      lastCompressionTime: this.lastCompressionTime,
      thresholds: this.thresholds
    };
  }

  /**
   * 清空上下文
   */
  clear() {
    const backupPath = this._backupCurrentContext();
    this.messages = [];
    this.incrementalTokenCount = 0;
    this.totalChars = 0;
    this.messageTokens.clear();
    return { cleared: true, backupPath };
  }
}

export const contextProtectorV7 = new ContextProtectorV7();
export default contextProtectorV7;

/**
 * OpenClaw 任务编排系统 v7.0 主入口
 * 
 * 整合八大核心模块，提供统一API
 * 保持与现有保护层 (~/.openclaw/protection/) 兼容性
 */
import { taskScorerV7 } from './scoring.js';
import { routePlannerV7 } from './routing.js';
import { contextProtectorV7 } from './context.js';
import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';
import { EventEmitter } from 'events';

class TaskOrchestratorV7 extends EventEmitter {
  constructor(options = {}) {
    super();

    // 核心模块 (已实现)
    this.scorer = taskScorerV7;
    this.router = routePlannerV7;
    this.context = contextProtectorV7;

    // ========= 其他模块核心实现 =========

    // 3. 超大任务执行器
    this.megaTaskExecutor = this._initMegaTaskExecutor();

    // 5. 子代理进度上报
    this.progressReporter = this._initProgressReporter();

    // 6. 安全模块
    this.security = this._initSecurityModule();

    // 7. 效率优化
    this.efficiency = this._initEfficiencyModule();

    // 8. 部署与运维
    this.ops = this._initOpsModule();

    // 配置
    this.config = {
      enabled: options.enabled !== false,
      compatibilityMode: options.compatibilityMode !== false, // 兼容旧版保护层
      baseDir: options.baseDir || path.join(os.homedir(), '.openclaw', 'orchestrator-v7'),
      ...options
    };

    // 任务存储
    this.tasks = new Map();
    this.taskQueue = [];

    // 初始化
    this._initDirectories();

    // 兼容旧版保护层API
    if (this.config.compatibilityMode) {
      this._setupCompatibilityLayer();
    }

    console.log('[OrchestratorV7] 初始化完成，已加载八大核心模块');
  }

  // ========= 对外API =========

  /**
   * 核心API: 提交任务并自动路由
   */
  submitTask(taskSpec, options = {}) {
    const taskId = options.taskId || `task_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;

    // 1. 安全检查
    const securityCheck = this.security.checkTask(taskSpec);
    if (!securityCheck.allowed) {
      throw new Error(`任务被安全模块拦截: ${securityCheck.reason}`);
    }

    // 2. 评分
    const scoreResult = this.scorer.score(taskSpec, options);

    // 3. 路由
    const routeResult = this.router.routeTask(taskSpec, options);

    // 4. 创建任务对象
    const task = {
      id: taskId,
      spec: taskSpec,
      score: scoreResult,
      route: routeResult,
      status: 'pending',
      createdAt: Date.now(),
      updatedAt: Date.now(),
      progress: 0,
      options,
      securityCheck
    };

    // 5. 存储任务
    this.tasks.set(taskId, task);

    // 6. 执行路由
    this._executeRoutedTask(task);

    // 触发事件
    this.emit('task:submitted', task);

    return {
      taskId,
      route: routeResult.route,
      score: scoreResult.total,
      timeoutSec: routeResult.timeout,
      memoryMB: routeResult.memoryMB,
      status: 'pending'
    };
  }

  /**
   * 获取任务状态
   */
  getTaskStatus(taskId) {
    const task = this.tasks.get(taskId);
    if (!task) return { exists: false };

    return {
      exists: true,
      ...task,
      runtime: Date.now() - task.createdAt
    };
  }

  /**
   * 取消任务
   */
  cancelTask(taskId) {
    const task = this.tasks.get(taskId);
    if (!task) return { success: false, error: 'task not found' };

    task.status = 'cancelled';
    task.updatedAt = Date.now();

    this.emit('task:cancelled', task);

    return { success: true, taskId };
  }

  /**
   * 处理新消息 (上下文保护)
   */
  handleMessage(message) {
    return this.context.addMessage(message);
  }

  /**
   * 兼容旧版保护层API: routeTask
   */
  routeTask(taskSpec, userOverrides = {}) {
    const result = this.router.routeTask(taskSpec, { userOverrides });
    // 转换为旧版格式
    return {
      route: result.route,
      isDowngraded: result.adjustmentFactor < 1,
      baseRoute: result.route,
      timeoutSec: result.timeout,
      stepTimeoutSec: result.route === 'STEP_ARCHIVE' ? 60 : undefined,
      checkpointEnabled: result.route === 'STEP_ARCHIVE' || result.route === 'MEGA_TASK',
      score: result.score,
      load: result.load
    };
  }

  // ========= 内部方法 =========

  _executeRoutedTask(task) {
    switch (task.route.route) {
      case 'DIRECT':
        this._executeDirectTask(task);
        break;
      case 'STEP_ARCHIVE':
        this._executeStepArchiveTask(task);
        break;
      case 'SPAWN_SUBAGENT':
        this._executeSubagentTask(task);
        break;
      case 'PARALLEL_SHARDS':
        this.megaTaskExecutor.executeShardedTask(task);
        break;
      case 'MEGA_TASK':
        this.megaTaskExecutor.executeMegaTask(task);
        break;
      default:
        this._executeDirectTask(task);
    }
  }

  _executeDirectTask(task) {
    // 简单任务直接执行
    task.status = 'running';
    task.updatedAt = Date.now();
    this.emit('task:started', task);

    // 模拟执行，实际应调用执行器
    setImmediate(() => {
      task.status = 'completed';
      task.progress = 100;
      task.updatedAt = Date.now();
      this.emit('task:completed', task);
      this.router.recordRouteResult(task.route.route, true, 0);
    });
  }

  _executeStepArchiveTask(task) {
    // 分步骤执行，支持断点续传
    task.status = 'running';
    task.updatedAt = Date.now();
    this.emit('task:started', task);

    // 模拟步骤执行
    const totalSteps = 5;
    let currentStep = 0;

    const runStep = () => {
      if (currentStep >= totalSteps || task.status === 'cancelled') {
        task.status = task.status === 'cancelled' ? 'cancelled' : 'completed';
        task.progress = 100;
        task.updatedAt = Date.now();
        this.emit('task:completed', task);
        this.router.recordRouteResult(task.route.route, true, Date.now() - task.createdAt);
        return;
      }

      currentStep++;
      task.progress = Math.round((currentStep / totalSteps) * 100);
      task.updatedAt = Date.now();
      this.emit('task:progress', task, { step: currentStep, totalSteps });

      // 保存检查点
      this.megaTaskExecutor.saveCheckpoint(task.id, {
        currentStep,
        totalSteps,
        progress: task.progress
      });

      setTimeout(runStep, 100);
    };

    runStep();
  }

  _executeSubagentTask(task) {
    // 子代理执行
    task.status = 'running';
    task.updatedAt = Date.now();
    this.emit('task:started', task);

    // 注册进度上报
    this.progressReporter.registerTask(task.id);

    // 模拟子代理执行
    setTimeout(() => {
      task.status = 'completed';
      task.progress = 100;
      task.updatedAt = Date.now();
      this.progressReporter.unregisterTask(task.id);
      this.emit('task:completed', task);
      this.router.recordRouteResult(task.route.route, true, Date.now() - task.createdAt);
    }, 500);
  }

  // ========= 模块初始化 =========

  _initMegaTaskExecutor() {
    const checkpoints = new Map();
    const shardResults = new Map();

    return {
      // 自动分片策略
      shardTask(task) {
        // 简单分片逻辑，根据任务复杂度拆分
        const shardCount = Math.min(10, Math.ceil(task.score.total / 2));
        const shards = [];
        for (let i = 0; i < shardCount; i++) {
          shards.push({
            id: `${task.id}_shard_${i}`,
            taskId: task.id,
            index: i,
            spec: task.spec,
            totalShards: shardCount
          });
        }
        return shards;
      },

      // 检查点保存
      saveCheckpoint(taskId, data) {
        checkpoints.set(taskId, {
          ...data,
          timestamp: Date.now()
        });
      },

      // 断点续传
      resumeTask(taskId) {
        return checkpoints.get(taskId) || null;
      },

      // 分片任务执行
      executeShardedTask(task) {
        const shards = this.shardTask(task);
        shardResults.set(task.id, []);

        task.status = 'running';
        task.updatedAt = Date.now();

        // 并行执行分片
        shards.forEach(shard => {
          // 模拟分片执行
          setTimeout(() => {
            const results = shardResults.get(task.id);
            results.push({ shardId: shard.id, success: true });
            shardResults.set(task.id, results);

            // 更新进度
            task.progress = Math.round((results.length / shards.length) * 100);
            task.updatedAt = Date.now();

            if (results.length === shards.length) {
              // 聚合结果
              task.status = 'completed';
              task.result = { shards: results };
              task.updatedAt = Date.now();
              task.progress = 100;
            }
          }, Math.random() * 200);
        });
      },

      // 超大任务执行
      executeMegaTask(task) {
        // 对于超过12分的超大任务，使用分片+队列执行
        const shards = this.shardTask(task);
        // 按优先级排队执行
        return { shards, queued: true };
      },

      // 结果聚合
      aggregateResults(taskId) {
        return shardResults.get(taskId) || [];
      }
    };
  }

  _initProgressReporter() {
    const registeredTasks = new Map();

    return {
      registerTask(taskId) {
        registeredTasks.set(taskId, {
          lastReport: 0,
          progress: 0,
          heartbeatCount: 0
        });
      },

      unregisterTask(taskId) {
        registeredTasks.delete(taskId);
      },

      // 上报进度
      reportProgress(taskId, progress, data = {}) {
        const taskInfo = registeredTasks.get(taskId);
        if (!taskInfo) return false;

        // 限流: 最多每秒上报1次
        const now = Date.now();
        if (now - taskInfo.lastReport < 1000 && progress !== 100) {
          return false;
        }

        taskInfo.lastReport = now;
        taskInfo.progress = progress;
        taskInfo.heartbeatCount++;
        taskInfo.lastData = data;

        // 触发进度事件
        orchestratorV7.emit('task:progress', { id: taskId, progress, ...data });

        return true;
      },

      // 自适应心跳: 根据任务时长调整心跳间隔
      getHeartbeatInterval(taskId) {
        const taskInfo = registeredTasks.get(taskId);
        if (!taskInfo) return 10000; // 默认10秒

        // 执行时间越长，心跳间隔越长
        if (taskInfo.heartbeatCount > 100) return 30000; // 30秒
        if (taskInfo.heartbeatCount > 30) return 20000; // 20秒
        return 10000;
      },

      // 输出解析容错
      parseProgressOutput(output) {
        // 匹配多种进度格式
        const patterns = [
          /\[PROGRESS\s*(\d+)%/i,
          /进度:?\s*(\d+)%/i,
          /(\d+)%.*(complete|done|finished)/i,
          /step\s*(\d+)\/(\d+)/i
        ];

        for (const pattern of patterns) {
          const match = output.match(pattern);
          if (match) {
            if (match.length === 3 && !isNaN(match[1]) && !isNaN(match[2])) {
              // step x/y 格式
              return Math.round((parseInt(match[1]) / parseInt(match[2])) * 100);
            } else if (!isNaN(match[1])) {
              // x% 格式
              return parseInt(match[1]);
            }
          }
        }

        return null; // 解析失败
      }
    };
  }

  _initSecurityModule() {
    return {
      // 命令白名单动态管理
      whitelist: new Set([
        'ls', 'cd', 'pwd', 'cat', 'head', 'tail', 'grep', 'find',
        'node', 'python', 'npm', 'yarn', 'git', 'docker', 'kubectl'
      ]),

      // 路径沙箱
      allowedPaths: [
        path.join(os.homedir(), '.openclaw'),
        path.join(os.homedir(), 'projects'),
        '/tmp'
      ],

      // 敏感信息脱敏
      sensitivePatterns: [
        /(sk-|api[_-]key|secret|password|token)[=:]\s*([a-zA-Z0-9_]+)/gi,
        /(Authorization|Bearer)\s+([a-zA-Z0-9_]+)/gi
      ],

      // 检查任务是否允许
      checkTask(taskSpec) {
        const specStr = JSON.stringify(taskSpec).toLowerCase();

        // 检查命令是否在白名单
        for (const cmd of specStr.match(/\b([a-z0-9_-]+)\b/g) || []) {
          if (cmd.length > 1 && !this.whitelist.has(cmd)) {
            // 简单黑名单，实际应更严格
            if (['rm', 'sudo', 'su', 'chmod', 'chown', 'mkfs', 'dd'].includes(cmd)) {
              return { allowed: false, reason: `危险命令被禁止: ${cmd}` };
            }
          }
        }

        // 检查路径是否在沙箱内
        const paths = specStr.match(/(\/[a-zA-Z0-9_/.-]+)/g) || [];
        for (const p of paths) {
          const resolved = path.resolve(p);
          const isAllowed = this.allowedPaths.some(allowed => resolved.startsWith(allowed));
          if (!isAllowed) {
            return { allowed: false, reason: `路径不在沙箱范围内: ${p}` };
          }
        }

        return { allowed: true };
      },

      // 脱敏敏感信息
      desensitize(text) {
        let result = text;
        for (const pattern of this.sensitivePatterns) {
          result = result.replace(pattern, (match, key) => `${key}=***`);
        }
        return result;
      },

      // 添加白名单命令
      addToWhitelist(cmd) {
        this.whitelist.add(cmd.toLowerCase());
      },

      // 移除白名单命令
      removeFromWhitelist(cmd) {
        this.whitelist.delete(cmd.toLowerCase());
      }
    };
  }

  _initEfficiencyModule() {
    // 连接池
    const connectionPool = new Map();
    // 异步日志队列
    const logQueue = [];
    let logProcessing = false;

    return {
      // 评分结果缓存 (已在scoring模块实现)

      // 异步日志
      log(level, message, data = {}) {
        logQueue.push({ level, message, data, timestamp: Date.now() });

        if (!logProcessing) {
          logProcessing = true;
          setImmediate(() => this._processLogQueue());
        }
      },

      _processLogQueue() {
        if (logQueue.length === 0) {
          logProcessing = false;
          return;
        }

        // 批量处理日志
        const batch = logQueue.splice(0, 100);
        // 写入文件或发送到日志系统
        const logPath = path.join(orchestratorV7.config.baseDir, 'logs', 'orchestrator.log');
        try {
          fs.appendFileSync(logPath, batch.map(l => 
            `${new Date(l.timestamp).toISOString()} [${l.level}] ${l.message} ${JSON.stringify(l.data)}\n`
          ).join(''));
        } catch (err) {
          // 忽略日志错误
        }

        setImmediate(() => this._processLogQueue());
      },

      // 连接池
      getConnection(type, key) {
        const poolKey = `${type}:${key}`;
        if (connectionPool.has(poolKey)) {
          return connectionPool.get(poolKey);
        }
        return null;
      },

      saveConnection(type, key, connection, ttl = 3600000) {
        const poolKey = `${type}:${key}`;
        connectionPool.set(poolKey, { connection, expiresAt: Date.now() + ttl });

        // 自动清理过期连接
        setTimeout(() => {
          if (connectionPool.get(poolKey)?.expiresAt <= Date.now()) {
            connectionPool.delete(poolKey);
          }
        }, ttl);
      }
    };
  }

  _initOpsModule() {
    return {
      // 健康检查端点
      getHealth() {
        return {
          status: 'ok',
          timestamp: Date.now(),
          version: '7.0.0',
          taskCount: orchestratorV7.tasks.size,
          queueLength: orchestratorV7.taskQueue.length,
          contextStats: orchestratorV7.context.getStats(),
          routeStats: orchestratorV7.router.getStats()
        };
      },

      // Prometheus 指标
      getMetrics() {
        const stats = orchestratorV7.router.getStats();
        const contextStats = orchestratorV7.context.getStats();

        return [
          `# HELP orchestrator_tasks_total Total number of tasks processed`,
          `# TYPE orchestrator_tasks_total counter`,
          `orchestrator_tasks_total ${orchestratorV7.tasks.size}`,
          ``,
          `# HELP orchestrator_context_token_ratio Current context token usage ratio`,
          `# TYPE orchestrator_context_token_ratio gauge`,
          `orchestrator_context_token_ratio ${contextStats.tokenRatio}`,
          ``,
          `# HELP orchestrator_route_success_rate Success rate per route`,
          `# TYPE orchestrator_route_success_rate gauge`
        ].concat(
          Object.entries(stats.routeStats).map(([route, data]) => 
            `orchestrator_route_success_rate{route="${route}"} ${data.successRate.replace('%', '')}`
          )
        ).join('\n');
      },

      // 配置热重载
      reloadConfig(newConfig) {
        orchestratorV7.config = { ...orchestratorV7.config, ...newConfig };
        // 重新初始化模块
        if (newConfig.thresholds) {
          orchestratorV7.context.thresholds = { ...orchestratorV7.context.thresholds, ...newConfig.thresholds };
        }
        if (newConfig.routeMappings) {
          orchestratorV7.router.updateRouteMappings(newConfig.routeMappings);
        }
        if (newConfig.weights) {
          orchestratorV7.scorer.setWeights(newConfig.weights);
        }
        return { success: true, config: orchestratorV7.config };
      },

      // 日志轮转
      rotateLogs() {
        const logDir = path.join(orchestratorV7.config.baseDir, 'logs');
        const logPath = path.join(logDir, 'orchestrator.log');

        if (fs.existsSync(logPath)) {
          const rotatedPath = path.join(logDir, `orchestrator_${Date.now()}.log`);
          fs.renameSync(logPath, rotatedPath);
          // 压缩旧日志
          // 实际环境可使用zlib压缩
          return { success: true, rotatedPath };
        }
        return { success: false, reason: 'log file not found' };
      }
    };
  }

  _initDirectories() {
    const dirs = [
      this.config.baseDir,
      path.join(this.config.baseDir, 'logs'),
      path.join(this.config.baseDir, 'checkpoints'),
      path.join(this.config.baseDir, 'backups')
    ];

    dirs.forEach(dir => {
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }
    });
  }

  _setupCompatibilityLayer() {
    // 兼容旧版保护层的API，实现常用方法
    this.submit = this.submitTask.bind(this);
    this.getStatus = this.ops.getHealth.bind(this.ops);
    this.summarize = this.context.compress.bind(this.context);
    this.securityCheck = this.security.checkTask.bind(this.security);

    console.log('[OrchestratorV7] 兼容层已启用，支持旧版保护层API');
  }
}

